class TradeManager {
    static let shared = TradeManager()
    
    private init() {}
    
    func executeTrade(symbol: String, quantity: Int, type: TradeType, completion: @escaping (Result<TradeResult, Error>) -> Void) {
        guard let url = URL(string: "https://api.tradingplatform.com/execute") else {
            completion(.failure(TradeError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("Bearer \(TokenManager.shared.getAccessToken())", forHTTPHeaderField: "Authorization")
        
        let body = [
            "symbol": symbol,
            "quantity": quantity,
            "type": type.rawValue
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(TradeError.noData))
                return
            }
            
            do {
                let result = try JSONDecoder().decode(TradeResult.self, from: data)
                completion(.success(result))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

