class TokenManager {
    static let shared = TokenManager()
    
    private init() {}
    
    func getAccessToken() -> String {
        guard let token = UserDefaults.standard.string(forKey: "access_token") else {
            return ""
        }
        return token
    }
    
    func setAccessToken(_ token: String) {
        UserDefaults.standard.set(token, forKey: "access_token")
    }
    
    func isAuthenticated() -> Bool {
        return !getAccessToken().isEmpty
    }
}

class PortfolioManager {
    static let shared = PortfolioManager()
    
    private var portfolio: [String: PortfolioItem] = [:]
    
    private init() {
        loadPortfolio()
    }
    
    func updatePortfolio(_ items: [PortfolioItem]) {
        for item in items {
            portfolio[item.symbol] = item
        }
        savePortfolio()
    }
    
    func getPortfolio() -> [PortfolioItem] {
        return Array(portfolio.values)
    }
    
    func getPortfolioItem(symbol: String) -> PortfolioItem? {
        return portfolio[symbol]
    }
    
    func addTransaction(_ transaction: Transaction) {
        if var item = portfolio[transaction.symbol] {
            item.quantity += transaction.quantity
            item.averagePrice = (item.averagePrice * (item.quantity - transaction.quantity) + transaction.price * transaction.quantity) / item.quantity
            portfolio[transaction.symbol] = item
        } else {
            portfolio[transaction.symbol] = PortfolioItem(
                symbol: transaction.symbol,
                quantity: transaction.quantity,
                averagePrice: transaction.price
            )
        }
        savePortfolio()
    }
    
    private func savePortfolio() {
        if let data = try? JSONEncoder().encode(Array(portfolio.values)) {
            UserDefaults.standard.set(data, forKey: "portfolio")
        }
    }
    
    private func loadPortfolio() {
        guard let data = UserDefaults.standard.data(forKey: "portfolio") else { return }
        if let items = try? JSONDecoder().decode([PortfolioItem].self, from: data) {
            for item in items {
                portfolio[item.symbol] = item
            }
        }
    }
}

struct PortfolioItem: Codable {
    let symbol: String
    var quantity: Int
    var averagePrice: Double
    var currentPrice: Double = 0.0
    
    var currentValue: Double {
        return Double(quantity) * currentPrice
    }
    
    var profitLoss: Double {
        return (currentPrice - averagePrice) * Double(quantity)
    }
    
    var profitLossPercentage: Double {
        return (profitLoss / (averagePrice * Double(quantity))) * 100
    }
}

struct Transaction: Codable {
    let id: String
    let symbol: String
    let quantity: Int
    let price: Double
    let type: TradeType
    let timestamp: Date
}

class TradingViewController: UIViewController {
    @IBOutlet weak var tableView: UITableView!
    @IBOutlet weak var portfolioValueLabel: UILabel!
    @IBOutlet weak var portfolioChangeLabel: UILabel!
    
    private var portfolioItems: [PortfolioItem] = []
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadPortfolio()
        setupBindings()
    }
    
    private func setupUI() {
        title = "Portfolio"
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "PortfolioCell")
    }
    
    private func loadPortfolio() {
        portfolioItems = PortfolioManager.shared.getPortfolio()
        updatePortfolioValue()
        tableView.reloadData()
    }
    
    private func updatePortfolioValue() {
        let totalValue = portfolioItems.reduce(0.0) { $0 + $1.currentValue }
        let totalProfitLoss = portfolioItems.reduce(0.0) { $0 + $1.profitLoss }
        
        portfolioValueLabel.text = String(format: "$%.2f", totalValue)
        portfolioChangeLabel.text = String(format: "%.2f%% ($%.2f)", 
                                          portfolioItems.isEmpty ? 0 : (totalProfitLoss / (totalValue - totalProfitLoss)) * 100,
                                          totalProfitLoss)
        portfolioChangeLabel.textColor = totalProfitLoss >= 0 ? .systemGreen : .systemRed
    }
    
    private func setupBindings() {
        // Bind to real-time updates
    }
    
    @IBAction func refreshButtonTapped(_ sender: UIBarButtonItem) {
        loadPortfolio()
    }
    
    @IBAction func tradeButtonTapped(_ sender: UIBarButtonItem) {
        let tradeVC = TradeViewController()
        let navController = UINavigationController(rootViewController: tradeVC)
        present(navController, animated: true)
    }
}

extension TradingViewController: UITableViewDataSource, UITableViewDelegate {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolioItems.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "PortfolioCell", for: indexPath)
        let item = portfolioItems[indexPath.row]
        
        cell.textLabel?.text = "\(item.symbol) (\(item.quantity))"
        cell.detailTextLabel?.text = String(format: "$%.2f (%.2f%%)", item.currentValue, item.profitLossPercentage)
        
        return cell
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let item = portfolioItems[indexPath.row]
        let detailVC = PortfolioDetailViewController()
        detailVC.item = item
        navigationController?.pushViewController(detailVC, animated: true)
    }
}

