class AuthenticationManager {
    static let shared = AuthenticationManager()
    
    private init() {}
    
    func authenticate(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "https://api.tradingplatform.com/auth/login") else {
            completion(.failure(TradeError.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body = [
            "username": username,
            "password": password
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(TradeError.noData))
                return
            }
            
            do {
                let response = try JSONDecoder().decode(AuthResponse.self, from: data)
                TokenManager.shared.setAccessToken(response.token)
                completion(.success(response.token))
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
}

